      const data = await fs.readFile(file, 'utf8');
      total += data.length;
    } catch (err) {
      console.error(`⚠️  Could not read "${file}":`, err.message);
      // decide whether to continue, re‑throw, or set a sentinel value
    }
  }

  console.log('total:', total);
}

// Example usage (wrap in an async IIFE or top‑level await):
