  // Map each filename to a promise that resolves to its length
  const lengthPromises = files.map(async (file) => {
    try {
      const data = await fs.readFile(file, 'utf8');
      return data.length;
    } catch (err) {
      console.error(`⚠️  Could not read "${file}":`, err.message);
      return 0;                     // treat a failed read as length 0
